"""
MKT Original Language Commentary — 2 Kings chapters 6–8
Run: python3 scripts/zc-original-2kings-6-8.py

Source data used:
- data/interlinear/2kings.json
- data/translation/draft/mediating/2kings.json (MKT text)
- data/commentary/mkt-original/2kings.json (existing: ch 2 v9 already written)

Key decisions in this range:
- sanwĕrîm (6:18): hapax — rendered "blindness/dazzlement"; only parallel is Gen 19:11
  (angels striking Sodomites), so carrying the divine-judgment register
- tĕśûʿāh/bĕśôrāh (7:9): "day of good news" — same root as NT euangelion; flagged
- môt yāmût / ḥāyōh tiḥyeh (8:10): two infinitive absolutes giving emphatic certainty
  to both recovery and death — the double oracle ambiguity treated as a feature, not a bug
- lĕmaʿan dāwîḏ (8:19): recurring Davidic-covenant formula; tied to 2 Sam 7 and the
  unconditional element of the royal promise
- ʾîš hāʾĕlōhîm throughout: not translated as "prophet" (nāḇîʾ) but "man of God" —
  the honorific marks Elisha's unique mediatorial status
- Gehazi's presence in ch 8 despite his leprosy in ch 5: the narrator does not explain;
  the juxtaposition appears deliberate (note in commentary without resolving)
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    """Merge new_data into existing without overwriting present entries."""
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

KINGS2 = {
  "6": {
    "1": "<p><strong>bĕnê hannĕbîʾîm</strong> — &lsquo;sons of the prophets.&rsquo; The word <em>bēn</em> marks discipleship, not biological relationship: these are members of a prophetic guild attached to Elisha. The plural construct <em>bĕnê</em> identifies a community of trainees, paralleling the guild communities at Bethel and Gilgal (2 Kgs 2:3, 4:38). The phrase places 2 Kings 6 firmly within the institutional prophetic tradition that runs from Samuel through Elijah to Elisha.</p>",
    "2": "<p>The sons of the prophets request to build a new meeting-place at the Jordan. <strong>nillāqaḥ</strong> (cohortative, &lsquo;let us take&rsquo;) expresses collective deliberation and initiative. The detail that the place where they live &lsquo;is too cramped (<em>ṣar</em>) for us&rsquo; uses the same root word (<em>ṣārar</em>) used for the constraint of Egypt; the community is outgrowing its space, the opposite of the covenant curse of shrinkage.</p>",
    "3": "<p>One of the sons requests Elisha to come with them: <strong>hôʾēl nā ûlēk ʾet-ʿăḇādêkā</strong> — &lsquo;please be willing to go with your servants.&rsquo; <em>hôʾîl</em> is a causative stem of <em>yāʾal</em>, meaning to be willing, to consent, to undertake. Elisha&rsquo;s one-word answer — <em>ʾēlēk</em>, &lsquo;I will go&rsquo; — mirrors the brevity of divine assent elsewhere (cf. the divine <em>lēkā</em> to Moses). The man of God follows his community into ordinary labor.</p>",
    "4": "<p>Simple narrative sequence using the waw-consecutive (<em>wayyēlek... wayĕhî... wayyipplû</em>): they went, they came, they felled. The rapid perfective narration (<em>wayyiqṭōl</em> forms) moves the story forward without elaboration. The Jordan is the scene of multiple Elisha miracles; the crossing point of covenant entry (Josh 3) becomes the site of the prophetic community&rsquo;s building project.</p>",
    "5": "<p><strong>ʾăhāh ʾăḏōnî</strong> — an interjection of distress: &lsquo;Oh, my master! It was borrowed.&rsquo; The key word is <strong>šāʾûl</strong> (borrowed, from <em>šāʾal</em>): the axe head was a loan. This is not a complaint about the loss alone but a legal anxiety — a borrowed tool that is lost creates an obligation of restitution (Exod 22:14). The exclamation foregrounds the narrator&rsquo;s interest in the socioeconomic vulnerability of the prophetic community.</p>",
    "6": "<p>Elisha asks, <strong>ʾānāh nāpal</strong> — &lsquo;where did it fall?&rsquo; Then he cuts a stick (<em>ʿēṣ</em>) and throws it at the place — and the iron floats. The verb <strong>wayyāṣēp</strong> (it floated) is from <em>ṣûp</em>, which means to float or swim; the same root used for the basket in Exod 2:3 (Moses&rsquo;s ark). The miracle is accomplished through the cast stick, an ordinary material whose use is not explained — the instrument is instrumental, the power is divine.</p>",
    "7": "<p><strong>hārîm lāk</strong> — &lsquo;pick it up for yourself.&rsquo; The imperative <em>hārîm</em> (lift/raise) with <em>lāk</em> (for yourself, reflexive) assigns the man both the instruction and the benefit. The miracle is not spectacular display but practical restoration — the borrowed iron is returned, the debt is cleared. The economy of grace operates through simple command and simple obedience.</p>",
    "8": "<p><strong>melek ʾărām nōḥēm milḥāmāh</strong> — &lsquo;the king of Aram was making war.&rsquo; The participle <em>nōḥēm</em> (deliberating, planning) from <em>yāʿaṣ</em> — to counsel, to plan. The king &lsquo;counsels with his officers&rsquo; (<em>nîʿāṣ ʾel-ʿăḇādāyw</em>) in tactical secrecy, saying &lsquo;at such-and-such a place (<em>māqôm</em>) shall be my camp.&rsquo; The king&rsquo;s secret military strategy is the foil for the prophet who knows all secrets.</p>",
    "9": "<p><strong>šālaḥ ʾîš hāʾĕlōhîm</strong> — &lsquo;the man of God sent word.&rsquo; <em>šālaḥ</em> (sent) with no object for the message marks urgency. His warning, <em>hišāmĕr mēʿăḇōr hammāqôm hazzeh</em> — &lsquo;take care not to pass that place&rsquo; — uses <em>hišāmēr</em> (guard yourself, beware) with <em>min-</em> (from), the standard warning construction. The information revealed is not from military intelligence but from divine revelation — the narration has the king of Israel discover that Elisha&rsquo;s intelligence is prophetic, not human (v12).</p>",
    "10": "<p>The king of Israel sent to the places the man of God warned about and &lsquo;was on his guard there&rsquo; — <strong>nišmar šām</strong> (guarded himself there). The Hebrew is terse; the king&rsquo;s response is immediate and effective. The narrator notes this happened &lsquo;more than once or twice&rsquo; (<em>lōʾ ʾaḥat wĕlōʾ šĕtāyim</em>, &lsquo;not once and not twice&rsquo;) — a Hebrew idiom for repeated occurrences, underscoring the pattern.</p>",
    "11": "<p><strong>wayyiṣṭarab lēb melek ʾărām</strong> — &lsquo;the heart of the king of Aram was troubled/stormy.&rsquo; The verb <em>sāʿar</em> in Niphal means to be stormy, disturbed, agitated — used of a stormy sea. The <em>lēb</em> (heart) as seat of understanding and decision is troubled because the confidentiality of royal counsel has been breached. The king suspects a traitor among his officers: <strong>mî mišelānû ʾel-melek yiśrāʾēl</strong> — &lsquo;which of us is for the king of Israel?&rsquo;</p>",
    "12": "<p>The officer&rsquo;s answer names Elisha: <strong>lōʾ ʾăḏōnî hammelek kî-ʾĕlîšāʿ hannāḇîʾ</strong> — &lsquo;none, my lord the king, but Elisha the prophet.&rsquo; The subsequent description — <em>yagîd lĕmelek yiśrāʾēl ʾet-haddĕḇārîm ʾăšer tĕdabbēr bĕḥadar miškābĕkā</em> — &lsquo;he tells the king of Israel the words you speak in your bedroom.&rsquo; The phrase <em>bĕḥadar miškābĕkā</em> (in your bedroom chamber) echoes Eccl 10:20 and emphasizes the most private possible speech. The prophet&rsquo;s knowledge is portrayed as total omniscience, an extension of YHWH&rsquo;s knowing all things (Ps 139:4).</p>",
    "13": "<p>The king commands, <strong>lĕkû rĕʾû ʾêkōh hûʾ</strong> — &lsquo;go, see where he is.&rsquo; The imperative plural and the king&rsquo;s intent — <em>wĕʾešlaḥ wĕʾeqqāḥeyhû</em>, &lsquo;I will send and seize him&rsquo; — use <em>lāqaḥ</em> (take/seize) for arrest. The response: <em>hinnēh bĕḏōṯān</em>, &lsquo;behold, he is in Dothan.&rsquo; Dothan appears in Gen 37:17 as the place where Joseph was sold by his brothers — the site carries connotations of betrayal and divine rescue.</p>",
    "14": "<p>The king sent a great army — <strong>sûs wārekeb wĕḥayil kāḇēḏ</strong> — &lsquo;horses and chariots and a heavy force.&rsquo; The adjective <em>kāḇēḏ</em> (heavy) is used of the Egyptians&rsquo; heavy/hard heart at the Exodus and of armies that overwhelm. They arrived <em>lāylāh</em> (at night) and surrounded the city — standard ANE siege preparation under cover of darkness.</p>",
    "15": "<p>Elisha&rsquo;s servant (<em>mĕšārēt</em>, attendant/minister — the same word used of Joshua&rsquo;s service to Moses, Exod 24:13) rises early and goes out. <strong>wayyiśśāʾ ʾet-ʿênāyw wayyarʾ</strong> — &lsquo;and he lifted his eyes and saw.&rsquo; The compound idiom <em>nāśāʾ ʿênayim</em> (lift the eyes) introduces visually significant moments throughout the OT (Gen 13:14; Josh 5:13). His cry to Elisha: <em>ʾăḥāh ʾăḏōnî mah naʿăśeh</em>, &lsquo;alas, my master, what shall we do?&rsquo;</p>",
    "16": "<p><strong>lōʾ-tîrāʾ kî rabbîm ʾăšer ʾittānû mēʾăšer ʾittām</strong> — &lsquo;Do not be afraid, for those who are with us are more than those who are with them.&rsquo; The chiasmic comparison (<em>rabbîm ʾăšer ʾittānû</em> vs. <em>ʾăšer ʾittām</em>) mirrors the formula of Num 14:9 and Josh 1:9. The key word is <em>rāb</em> (many, great): the unseen army is numerically greater, though invisible. This is the Hebrew equivalent of Rom 8:31: &lsquo;if God is for us, who can be against us?&rsquo; — the numerical calculus of faith.</p>",
    "17": "<p>Elisha&rsquo;s prayer: <strong>YHWH pĕqaḥ-nā ʾet-ʿênāyw wĕyirʾeh</strong> — &lsquo;LORD, please open his eyes that he may see.&rsquo; The verb <em>pāqaḥ</em> (open — specifically of eyes) is used in Gen 3:5 (the serpent&rsquo;s promise: &lsquo;your eyes will be opened&rsquo;) and Gen 21:19 (Hagar&rsquo;s eyes opened to see the well). Divine eye-opening is always a gift of sight beyond ordinary seeing. The servant sees <strong>sûsîm wĕrekeb ʾēš</strong> — &lsquo;horses and chariots of fire.&rsquo; The phrase exactly parallels 2:11 (Elijah&rsquo;s ascent) and brackets the Elisha narrative with fire-chariots at beginning and end of the prophetic succession.</p>",
    "18": "<p>Elisha prays a second time: <strong>hak nā ʾet-haggôy-hazzeh bassanwĕrîm</strong> — &lsquo;please strike this people with blindness/dazzlement.&rsquo; The word <em>sanwĕrîm</em> is a hapax legomenon (appears only here and Gen 19:11, where the angels strike the Sodomites with the same word). It likely derives from a root related to dazzling brightness, not total darkness — a supernatural disorientation of sight. The Arameans are not blinded in the medical sense (they can still walk, following Elisha); they are divinely confused about where they are and who they are following.</p>",
    "19": "<p>Elisha&rsquo;s deception of the disoriented Arameans — <strong>lōʾ zeh hadderek wĕlōʾ zōʾt hāʿîr</strong> — &lsquo;This is not the way and this is not the city.&rsquo; He leads them to Samaria, the capital. The verb <em>ʾōlîk ʾetkem</em> (I will lead you) uses the Hiphil of <em>hālak</em> — causative leading, typically used of God leading his people (the Exodus). Elisha is re-enacting the divine leading of the desert, but to the center of Israel&rsquo;s power rather than the promised land.</p>",
    "20": "<p>On arrival in Samaria, Elisha prays a third time: <strong>YHWH pĕqaḥ ʾet-ʿênê ʾēlleh wĕyirʾû</strong> — &lsquo;LORD, open the eyes of these men that they may see.&rsquo; The same verb <em>pāqaḥ</em> used in v17 creates a double eye-opening: the servant&rsquo;s eyes opened to see the divine army; the Arameans&rsquo; eyes opened to see themselves surrounded. The verse contains an ironic inclusio between v17 and v20: both use &lsquo;open his/their eyes&rsquo; to reveal reality, but one revelation is salvation and the other is captivity.</p>",
    "21": "<p>The king of Israel&rsquo;s question: <strong>hakkōh ʾakkeh ʾăbî hakkōh ʾakkeh</strong> — &lsquo;Shall I strike them, my father? Shall I strike them?&rsquo; The doubled question with <em>hakkōh</em> (thus/in this manner) expresses eagerness. The address <em>ʾāḇî</em> (my father) to Elisha is the same address Elisha used for Elijah (2:12); it marks the prophet as a paternal authority over the king. The repetition of the question intensifies both the eagerness and the waiting for prophetic authorization.</p>",
    "22": "<p>Elisha&rsquo;s prohibition: <strong>lōʾ takkeh</strong> — &lsquo;You shall not strike them.&rsquo; His reasoning uses a rhetorical question: <em>ʾăšer šāḇîtā bĕḥarbekā ûbĕqaštĕkā</em>, &lsquo;those you have captured with your sword and your bow.&rsquo; The point is that these men were not captured by Israel&rsquo;s military force at all — God delivered them. Elisha then commands: <em>śîm lāhem leḥem wāmayim wĕyōʾkĕlû wĕyišĕtû</em>, &lsquo;set bread and water before them that they may eat and drink.&rsquo; The feeding of an enemy army by prophetic command has no parallel in the OT.</p>",
    "23": "<p><strong>wayyikrōt lāhem kĕrāh gĕḏôlāh</strong> — &lsquo;he prepared a great feast for them.&rsquo; <em>kārāh</em> (to prepare a feast) is used of festive meals in Gen 31:54 and Prov 9:2. The great feast given to enemies recalls the covenant meal (cf. Exod 24:11, the elders eating before God on Sinai). After eating and drinking, <em>wayyĕšallĕḥēm</em> (he sent them away) — the Piel of <em>šālaḥ</em>, the same verb used of releasing slaves and prisoners. The Aramean incursions then ceased: <em>lōʾ-yāsĕpû ʿôḏ</em> — &lsquo;they came no more.&rsquo;</p>",
    "24": "<p><strong>wayyĕhî ʾaḥărê-kēn</strong> — &lsquo;after this.&rsquo; The narrator&rsquo;s transitional formula signals a major scene shift: the Aramean king Ben-hadad (<em>ben-hadad melek ʾărām</em>) musters his entire army (<em>ʾet-kol-maḥănēhû</em>) and goes up to besiege Samaria. The verb <em>wayyiṣōr</em> (laid siege) from <em>ṣûr</em> marks prolonged military pressure. This is the systematic siege that will produce the famine of vv25-33.</p>",
    "25": "<p><strong>wayhî rāʿāḇ gāḏôl bĕšōmĕrôn</strong> — &lsquo;there was a great famine in Samaria.&rsquo; The severity is measured by market prices: <em>ḥōmĕr rōʾš ḥamôr bĕŠmōnîm kesep</em>, &lsquo;a donkey&rsquo;s head for eighty shekels.&rsquo; The donkey is a non-kosher animal (Lev 11:4-7), its head the least valuable part. Normal price of a lamb at Passover: approximately 5 shekels. The price escalation represents a factor of over 200: the covenant economy has collapsed entirely, as Deut 28:52-57 predicted for a siege.</p>",
    "26": "<p><strong>wayyiṣʿaq ʾēlāyw ʾiššāh</strong> — &lsquo;a woman cried out to him.&rsquo; The verb <em>ṣāʿaq</em> (cry out, cry for help) is used throughout the OT for the cry of the oppressed (Exod 2:23; Judg 3:15). The king is addressed as <em>ʾăḏōnî hammelek</em> (my lord the king), the standard petition formula — the woman is using the formal channels of royal justice.</p>",
    "27": "<p>The king&rsquo;s response uses two Hebrew nouns in a rhetorical pair: <strong>min-haggōren ʾô min-hayyāqeb</strong> — &lsquo;from the threshing floor or from the winepress?&rsquo; These are the two sources of grain and wine — but the king&rsquo;s bitter question means: if YHWH won&rsquo;t help you, what source of provision remains? The king has no grain from the floor and no wine from the press during a siege. His question is a confession of helplessness dressed as a rhetorical question.</p>",
    "28": "<p>The king asks what is wrong; the woman&rsquo;s account is a nightmare: her neighbor said <strong>tĕnî ʾet-binkê wĕnōklennû hayyôm</strong> — &lsquo;give your son so we can eat him today.&rsquo; The verb <em>ʾākal</em> (eat) and the causative <em>nātan</em> (give) in this context carry the full weight of Deut 28:53: &lsquo;you shall eat the offspring of your own body, the flesh of your sons and daughters.&rsquo; The covenant curse is not a hyperbole; it is literally enacted.</p>",
    "29": "<p>The woman&rsquo;s account continues: <strong>wattōʾmer ûḇannāh bĕneyhā</strong> — &lsquo;and on the next day she hid her son.&rsquo; The verb <em>ṣāpan</em> (hide, conceal) used here for concealing a child recalls Exod 2:2-3 (the mother who hid Moses for three months). The reversal is devastating: in Exodus, a mother concealed a child to save him from slaughter; here, a mother conceals a child from a woman who wants to eat him. The Deuteronomic curse has inverted the Exodus rescue.</p>",
    "30": "<p>When the king heard the woman&rsquo;s words, <strong>wayyiqraʿ ʾet-bĕḡādāyw</strong> — &lsquo;he tore his clothes.&rsquo; The royal mourning gesture (cf. 2 Sam 3:31) expresses anguish and helplessness. The narrator adds that he was passing along the wall — his torn garments were visible to the people below (<em>wĕhāʿām hišqîp wĕhinnēh hassaq</em>, &lsquo;and the people looked, and behold, sackcloth inside&rsquo;). The king&rsquo;s private mourning becomes a public spectacle.</p>",
    "31": "<p>The king&rsquo;s oath against Elisha: <strong>kōh-yaʿăśeh lî ʾĕlōhîm wĕkōh yôsîp ʾim-yaʿămōd rōʾš ʾĕlîšāʿ</strong> — &lsquo;may God deal with me... if the head of Elisha remains on him today.&rsquo; The self-imprecatory formula (<em>kōh yaʿăśeh... wĕkōh yôsîp</em>, &lsquo;so may he do and so may he add&rsquo;) is the standard Hebrew oath formula (cf. 1 Sam 14:44; Ruth 1:17). The blame directed at Elisha (rather than at YHWH) reflects a pattern of scapegoating the prophet for divine judgment.</p>",
    "32": "<p>Elisha is sitting with the elders (<em>zĕqēnîm</em>). He sees the messenger coming: <strong>rĕʾîtem kî-šālaḥ ben-hammĕraṣṣēaḥ hazzeh</strong> — &lsquo;see how this son of a murderer has sent.&rsquo; The phrase <em>ben-hammĕraṣṣēaḥ</em> (son of a murderer) is a Hebrew idiom: <em>bĕn + noun</em> = one characterized by that quality (cf. <em>bĕn-ḥayil</em>, &lsquo;son of valor&rsquo; = valiant man). Elisha&rsquo;s preemptive announcement of the messenger&rsquo;s arrival demonstrates prophetic foreknowledge a second time in the chapter.</p>",
    "33": "<p>The messenger arrives and the king&rsquo;s despairing words: <strong>hinnēh zōʾt hārāʿāh mēʾēt YHWH mah-ʾôḥil lĕYHWH ʿôḏ</strong> — &lsquo;this disaster is from YHWH — what further hope is there from YHWH?&rsquo; The word <em>rāʿāh</em> (disaster, evil) is the same word used throughout for moral evil and for catastrophe; here it describes the siege and famine as YHWH&rsquo;s act. The king&rsquo;s <em>mah-ʾôḥil</em> (what hope?) is a rare verb form (<em>yāḥal</em>, to wait/hope) — the despairing acknowledgment that YHWH is the source of the crisis and the only possible source of relief.</p>"
  },
  "7": {
    "1": "<p>Elisha&rsquo;s oracle begins with <strong>šimʿû dĕbar-YHWH</strong> — &lsquo;hear the word of YHWH&rsquo; — the standard call to prophetic attention. The prediction: <strong>kĕsāʾāh sōlet bĕšeqel ûsātayim śĕʿōrîm bĕšeqel</strong> — &lsquo;a seah of fine flour for a shekel, two seahs of barley for a shekel.&rsquo; This is a dramatic price reversal from 6:25 (where a donkey&rsquo;s head costs 80 shekels). The timing: <em>kāʿēt māḥār</em>, &lsquo;about this time tomorrow.&rsquo; The preciseness of the timing is part of the prophecy&rsquo;s verification function.</p>",
    "2": "<p>The officer&rsquo;s objection: <strong>wĕhinnēh ʾĕlōhîm ʿōśeh ʾărubbôt baššāmāyim hăyihyeh haddāḇār hazzeh</strong> — &lsquo;even if YHWH were to make windows in heaven, could this thing happen?&rsquo; The phrase <em>ʾărubbôt baššāmāyim</em> (windows in heaven) is taken directly from Gen 7:11 — the flood narrative where &lsquo;the windows of heaven were opened.&rsquo; The officer&rsquo;s sarcasm uses the flood idiom to mock the possibility of supernatural provision. Elisha&rsquo;s response: <em>hinnĕkā rōʾeh bĕʿênêkā ûmišām lōʾ tōʾkēl</em>, &lsquo;you shall see it with your own eyes but not eat of it.&rsquo;</p>",
    "3": "<p>The lepers at the gate: <strong>ʾarbaʿāh ʾănāšîm hāyû mĕṣōrāʿîm</strong> — &lsquo;four men with skin disease.&rsquo; The word <em>mĕṣōrāʿîm</em> (from <em>ṣāraʿ</em>) denotes a severe skin condition requiring social exclusion (Lev 13-14); their position at the gate entrance places them at the margin between the city and the outside — they are excluded from the community. Their logic is expressed in a binary: they can neither enter the city (famine within) nor stay at the gate (starvation there too).</p>",
    "4": "<p>The lepers&rsquo; reasoning uses the imperfect tense for both contingencies: <strong>ʾim-ʾāmarnû nāḇôʾ hāʿîr wĕhārāʿāb bāʿîr ûmātnû šām</strong> — &lsquo;If we say, let us enter the city, the famine is in the city and we will die there.&rsquo; The structure is a classic Hebrew conditional: <em>ʾim + imperfect... wĕ-perfect</em>. The conclusion: <em>wĕnābôʾ ʾel-maḥănēh ʾărām ʾim-yĕḥayûnû niḥyeh</em>, &lsquo;if they spare us alive, we shall live; if they kill us, we shall die.&rsquo; This double conditional (<em>ʾim-yĕḥayûnû / ʾim-yĕmîtûnû</em>) is the syntax of a calculated gamble on mercy.</p>",
    "5": "<p><strong>wayyāqûmû bannešep lābōʾ ʾel-maḥănēh ʾărām</strong> — &lsquo;they rose at twilight to go to the Aramean camp.&rsquo; <em>Nešep</em> means twilight, the ambiguous light between day and night. The temporal detail heightens suspense. They arrive at the edge of the camp (<em>qĕṣēh maḥănēh ʾărām</em>) — and <strong>wĕhinnēh ʾên-šām ʾîš</strong>, &lsquo;and behold, there was no one there.&rsquo; The <em>hinnēh</em> particle introduces a dramatic reversal discovery.</p>",
    "6": "<p>The divine action: <strong>waʾdōnāy hišmîaʿ ʾet-maḥănēh ʾărām qôl rekeb</strong> — &lsquo;the Lord had made the Aramean camp hear the sound of chariots.&rsquo; The verb <em>hišmîaʿ</em> (Hiphil of <em>šāmaʿ</em>, to hear) means to cause to hear — God made them hear a sound that was not physically present. The sounds catalogued: chariots (<em>rekeb</em>), horses (<em>sûs</em>), a great army (<em>ḥayil gāḏôl</em>). The Arameans interpreted it as a coalition of Egypt and the Hittite kings (Israel hired them, they said) — a false reading of a true divine signal.</p>",
    "7": "<p>The rout of the Arameans: <strong>wayyāqûmû wayyanûsû bannešep</strong> — &lsquo;they rose and fled at twilight.&rsquo; The same word <em>nešep</em> as v5 — the lepers came at twilight; the Arameans fled at twilight. The temporal irony binds the two groups: the marginalized move toward hope while the powerful move in terror. They abandoned their camp fully equipped: <em>ʾohŏlêhem wĕsûsêhem waḥămōrêhem</em> — tents, horses, donkeys — and <em>wayyibrĕḥû ʾel-napšām</em>, &lsquo;they fled for their lives.&rsquo; <em>Nepeš</em> (life, soul) here means their physical survival.</p>",
    "8": "<p>The lepers&rsquo; discovery: <strong>wayyābōʾû hamĕṣōrāʿîm hāʾēlleh ʾel-qĕṣēh hammahăneh</strong> — &lsquo;these lepers came to the edge of the camp.&rsquo; They &lsquo;came to&rsquo; the edge, ate, drank, carried off silver, gold, and clothing. The verb <em>wayyiśśĕʾû</em> (they carried off) followed by the accumulation of wealth: <em>kesep wĕzāhāḇ ûbĕḡāḏîm</em>. Their immediate response is private hoarding — they carry it and hide it (<em>wayyiṭmĕnû</em>, from <em>ṭāman</em>, to bury/conceal) before returning for more.</p>",
    "9": "<p><strong>wayyōʾmĕrû ʾîš ʾel-rēʿēhû lōʾ-kēn ʾănaḥnû ʿōśîm</strong> — &lsquo;They said to one another, We are not doing right.&rsquo; The word <em>kēn</em> (right, thus) in the construction <em>lōʾ-kēn</em> means &lsquo;not rightly.&rsquo; The key phrase: <strong>yôm-bĕśôrāh hûʾ</strong> — &lsquo;this is a day of good news.&rsquo; <em>Bĕśôrāh</em> is the Hebrew equivalent of <em>euangelion</em> — the announcement of something that changes everything. The same root (Piel of <em>bāśar</em>) is used in Isa 52:7 (&lsquo;how beautiful are the feet of him who brings good news&rsquo;). The lepers recognize their obligation to proclaim, not hoard, the discovery.</p>",
    "10": "<p>The lepers call to the city gatekeepers — <strong>wayyiqrĕʾû ʾel-šōʿar hāʿîr</strong> — and report: <em>bānû ʾel-maḥănēh ʾărām wĕhinnēh ʾên-šām ʾîš wĕqôl ʾāḏām</em>, &lsquo;we came to the Aramean camp and behold, there was no one there, and no sound of a human voice.&rsquo; The repeated <em>hinnēh</em> (behold) marks the surprise. The compound negative (<em>ʾên-šām ʾîš</em> + <em>wĕqôl ʾāḏām</em>) emphasizes total abandonment — both persons and sounds are absent.</p>",
    "11": "<p>The gatekeepers call out; the report reaches the palace: <strong>wayyuggad lĕbêt hammelek pĕnîmāh</strong> — &lsquo;it was reported to the king&rsquo;s house inside.&rsquo; The adverb <em>pĕnîmāh</em> (inside, inward) and the passive <em>wayyuggad</em> (it was told) shift the verb to the divine passive — news reaches the center of power by unseen agents.</p>",
    "12": "<p>The king rises at night — the same ironic timing as the Aramean flight (twilight/night). His suspicion: <strong>ʾaggîḏāh-nā lākem ʾēt ʾăšer-ʿāśû-lānû ʾărām</strong> — &lsquo;let me tell you what the Arameans have done.&rsquo; He suspects a trap: <em>yōdĕʿîm hēmmāh kî-rĕʿēbîm ʾănaḥnû</em>, &lsquo;they know we are hungry.&rsquo; His military logic is sound — but his reading of the situation is completely wrong. The narrative irony is that the king&rsquo;s elaborate suspicion keeps him from acting on genuine deliverance.</p>",
    "13": "<p>The king&rsquo;s servant suggests a modest reconnaissance: <strong>wĕyišlĕḥû wĕnirʾeh</strong> — &lsquo;let us send and see.&rsquo; The argument: the horses that remain are &lsquo;like all the multitude of Israel that will be destroyed&rsquo; (<em>kĕkol-hāmôn yiśrāʾēl ʾăšer niš&rsquo;ārû-ḇām</em>). The syntax implies they are expendable — even if it&rsquo;s a trap, the loss of five horses equals only the guaranteed loss of dying in the city. This is the logic of the lepers in v4, applied by the king&rsquo;s servants: marginal losses are acceptable when total loss is the alternative.</p>",
    "14": "<p>Two chariot teams are sent (<em>šĕnê rikbê sûsîm</em>). The king commands: <strong>lĕkû ûrĕʾû</strong> — &lsquo;go and see.&rsquo; The brief direct command uses the plural imperative without elaboration — the mission is simple. The king adds: <em>wĕšallĕḥēm ʾaḥărê maḥănēh ʾărām</em>, &lsquo;send them after the Aramean camp.&rsquo; The verb <em>šālaḥ</em> (send forth) with <em>ʾaḥărê</em> (after) marks pursuit — the king thinks this might be a rearguard trap.</p>",
    "15": "<p>The scouts follow to the Jordan: <strong>wayyēlĕkû ʾaḥărêhem ʿaḏ-hayyardēn</strong>. The road was littered with garments and equipment the Arameans threw off in their panic — <strong>kol-hadderek mĕlēʾāh bĕḡāḏîm ûkēlîm</strong>. The word <em>kēlîm</em> (vessels, equipment) indicates military gear abandoned in flight. The scouts return and report. The abandoned equipment confirms the divine rout — the Arameans stripped themselves to flee faster, a sign of total panic.</p>",
    "16": "<p><strong>wayyēṣēʾ hāʿām wayyābōzẑû ʾet-maḥănēh ʾărām</strong> — &lsquo;the people went out and plundered the Aramean camp.&rsquo; The verb <em>bāzaz</em> (to plunder, spoil) is used of the Israelites plundering Egypt at the Exodus (Exod 12:36). The echo is intentional: YHWH&rsquo;s deliverance of Israel from a siege produces the same plundering of the enemy&rsquo;s goods. The price of flour immediately fulfills Elisha&rsquo;s prophecy: <em>kĕsāʾāh sōlet bĕšeqel ûsātayim śĕʿōrîm bĕšeqel</em>, exactly as predicted.</p>",
    "17": "<p><strong>wĕhammelek hipqîd ʾet-haššālîš ʾăšer niš&rsquo;ān ʾal-yāḏô</strong> — &lsquo;the king placed the officer on whose hand he had leaned in charge of the gate.&rsquo; <em>Niš&rsquo;ān ʾal-yāḏô</em> (leaned on his hand) — the physical posture of royal support/dependence echoes the idiom of 2 Kgs 5:18 (Naaman leaning on his master&rsquo;s arm). This officer is the one who mocked the prophecy (v2). The passive <em>wayĕḇûsēhû</em> — &lsquo;the people trampled him&rsquo; — fulfills Elisha&rsquo;s word: seeing but not eating.</p>",
    "18": "<p>The narrative repeats the prophecy verbatim — <strong>kĕdabbēr ʾîš hāʾĕlōhîm ʾel-hammelek</strong> (as the man of God had spoken to the king). The repetition is the narrator&rsquo;s verification: the prophetic word was given (v1-2), doubted (v2b), and is now confirmed (vv18-20). The structural feature — prediction, doubt, fulfillment, verification — is typical of the Kings narrator&rsquo;s method of establishing prophetic credentials.</p>",
    "19": "<p>The doubting officer&rsquo;s words are recalled: <strong>ʾapōt bĕšāmayim hăyihyeh haddāḇār hazzeh</strong> — &lsquo;even if YHWH were to make windows in heaven, could this thing happen?&rsquo; The repetition serves as the legal basis for Elisha&rsquo;s specific judgment (<em>hinnĕkā rōʾeh bĕʿênêkā ûmiššām lōʾ tōʾkēl</em>) — the man who disbelieved the word will see but not benefit. The word <em>rāʾāh</em> (see) connects to the eye-opening theme of chapter 6.</p>",
    "20": "<p><strong>wayyĕhî-lô kēn</strong> — &lsquo;and it happened exactly so to him.&rsquo; The terse narrator&rsquo;s formula (<em>kēn</em>, thus/so) closes the Elisha prophecy narrative with economical precision: the officer was trampled in the gate and died. The waw-consecutive perfect <em>wayyāmot</em> (and he died) is the final word. The narrative circle: prophecy given → doubted → fulfilled → fulfilled exactly. Each link is verbally confirmed by the narrator.</p>"
  },
  "8": {
    "1": "<p>The chapter opens with <strong>wĕʾĕlîšāʿ dibber</strong> — &lsquo;Elisha had spoken&rsquo; — a pluperfect construction in context (he had previously warned the Shunammite). The reason for urgency: <strong>qārāʾ YHWH lārāʿāb</strong> — &lsquo;YHWH has called for a famine.&rsquo; The Piel of <em>qārāʾ</em> (call, summon) makes YHWH the active agent of the famine — it is a divine summons, not a natural disaster. The seven-year duration (<em>šebaʿ šānîm</em>) echoes Joseph&rsquo;s seven-year famine (Gen 41:54), framing this as another exodus-type situation requiring prophetic guidance for survival.</p>",
    "2": "<p>The woman does exactly as the man of God commanded: <strong>wattemah wĕtaʿaś kidĕbar ʾîš hāʾĕlōhîm</strong> — &lsquo;she arose and did according to the word of the man of God.&rsquo; The verb <em>wattēšeb bĕʾereṣ pĕlištîm</em> — &lsquo;she lived in the land of the Philistines.&rsquo; The Philistine land as a refuge for an Israelite woman is unexpected; it recalls Ruth&rsquo;s sojourn in Moab. The narrator notes she was there <em>šebaʿ šānîm</em> — seven years, precisely the famine&rsquo;s duration.</p>",
    "3": "<p>After seven years: <strong>wayyāšob hāʾiššāh mēʾereṣ pĕlištîm</strong> — &lsquo;the woman returned.&rsquo; The verb <em>šûb</em> (return) is theologically loaded in Kings: it is the call to covenant return (<em>tĕšûḇāh</em>), the hope of restoration. The woman goes to the king to appeal for her house and land: <strong>wattēṣēʾ liṣʿōq ʾel-hammelek ʾel-bêtāh wĕʾel-śāḏĕhā</strong> — &lsquo;she went out to cry out to the king for her house and land.&rsquo; The verb <em>ṣāʿaq</em> (cry out) is again the legal appeal to royal justice.</p>",
    "4": "<p>The king was talking with Gehazi: <strong>wĕhammelek mĕdabbēr ʾel-gēḥăzî naʿar ʾîš hāʾĕlōhîm</strong> — &lsquo;the king was talking with Gehazi the servant of the man of God.&rsquo; The participial construction (<em>mĕdabbēr</em>) marks the scene as simultaneously occurring with the woman&rsquo;s arrival. Gehazi&rsquo;s presence here is unexplained — in ch 5:27 he was struck with leprosy permanently. The narrator does not resolve the tension; some interpreters read this as a flashback (before the leprosy episode) or as a different period. The question remains open in the text.</p>",
    "5": "<p>While Gehazi is recounting how Elisha raised the dead child, <strong>wĕhinnēh hāʾiššāh ʾăšer-hĕḥěyyāh ʾet-bĕnāh zōʿĕqet ʾel-hammelek</strong> — &lsquo;behold, the woman whose son he had raised was crying out to the king.&rsquo; The <em>hinnēh</em> (behold) marks the providential coincidence: Gehazi is telling the exact story about the exact woman at the exact moment she arrives. This kind of narrative coincidence (<em>miqqreh</em>) is treated in Kings as YHWH&rsquo;s invisible orchestration.</p>",
    "6": "<p>The king assigns an officer to restore the woman&rsquo;s property: <strong>wĕkol-tĕbûʾōt haśśāḏeh mēʾāz ʿăzōbāh hāʾāreṣ wĕʿad-ʿattāh</strong> — &lsquo;all the produce of the field from the time she left the land until now.&rsquo; The phrase <em>wĕʿad-ʿattāh</em> (until now) extends the restoration backward in time — the king does not merely return the land but compensates for all income lost during the seven years. This is the OT equivalent of the year of Jubilee&rsquo;s restoration principle (Lev 25:27-28).</p>",
    "7": "<p>Elisha travels to Damascus: <strong>wayyābōʾ ʾĕlîšāʿ dammāśeq</strong>. The reason for the journey is not given; the man of God moves where YHWH directs. Ben-hadad the king of Syria was ill (<em>ḥōleh</em>). When told &lsquo;the man of God has come here&rsquo; (<em>ʾîš hāʾĕlōhîm bā ʿad-hēnnāh</em>), the king sends Hazael with a gift (<em>minḥāh</em>) — the same word used for tribute and gift-offering in diplomatic and religious contexts.</p>",
    "8": "<p>Ben-hadad commands Hazael: <strong>qah bĕyāḏĕkā minḥāh wĕlēk liqrāʾt ʾîš hāʾĕlōhîm wĕdāraštā ʾet-YHWH mēʾittô</strong> — &lsquo;take a gift and go meet the man of God and inquire of YHWH through him.&rsquo; The verb <em>dāraš</em> (inquire/seek) is the standard OT term for consulting a prophet: <em>dāraš YHWH</em> (seek YHWH). Ben-hadad, the Aramean king, uses YHWH&rsquo;s name and seeks his prophet — a recognition that transcends national boundaries, as Naaman&rsquo;s healing did.</p>",
    "9": "<p>Hazael brings a lavish gift: <strong>ʿeśrîm gāmāl massāʾ mikkol-ṭûb dammāśeq</strong> — &lsquo;forty camel loads of every good thing of Damascus.&rsquo; The phrase <em>mikkol-ṭûb</em> (from all the good things) echoes the &lsquo;good of the land&rsquo; language in Gen 45:18-20 (Jacob&rsquo;s arrival in Egypt). Hazael stands before Elisha and calls him <em>binkā ben-hadad</em>, &lsquo;your son Ben-hadad&rsquo; — the king addresses the prophet as a superior.</p>",
    "10": "<p>Elisha&rsquo;s double-edged oracle: <strong>lēk ʾĕmōr-lô ḥāyōh tiḥyeh</strong> — &lsquo;Go tell him, you will certainly recover.&rsquo; The infinitive absolute + imperfect construction (<em>ḥāyōh tiḥyeh</em>) expresses certainty: he will definitely recover from the illness. But then: <strong>wĕhirʾanî YHWH kî môt yāmût</strong> — &lsquo;but YHWH has shown me that he will certainly die.&rsquo; The same grammatical certainty (<em>môt yāmût</em>, infinitive absolute + imperfect) applies to his death. The two certainties are not contradictory: Ben-hadad will recover from this illness but will die by another means — murder by Hazael (v15).</p>",
    "11": "<p><strong>wayyaʿămēd ʾet-pānāyw wayyāśem ʿad-bōš</strong> — &lsquo;he fixed his gaze on him and stared until he was ashamed/embarrassed.&rsquo; The verb <em>wayyaʿămēd</em> (made to stand, fixed) with <em>pānāyw</em> (his face) means he held his countenance motionless. The phrase <em>ʿad-bōš</em> (until shame) — Hazael becomes uncomfortable under the prophet&rsquo;s unseeing gaze. Elisha then <em>wayyēḇk ʾîš hāʾĕlōhîm</em> — wept. The man of God&rsquo;s tears are the only explicit prophetic weeping in Kings (cf. Jeremiah&rsquo;s tears in Lamentations).</p>",
    "12": "<p>Hazael asks, <strong>maddûaʿ ʾăḏōnî ḇōkeh</strong> — &lsquo;why does my lord weep?&rsquo; Elisha&rsquo;s answer catalogues the atrocities: <em>kî yōdaʿtî ʾēt ʾăšer-taʿăśeh liḇnê yiśrāʾēl rāʿāh</em> — &lsquo;because I know the evil you will inflict on Israel.&rsquo; The list — burning their fortresses, killing their young men with the sword, dashing their children to pieces (<em>tĕraṭṭēš</em>), ripping open pregnant women — uses verbs that occur in the devastation oracles of Amos (1:13) and Hosea (13:16). The prophet weeps not for Hazael&rsquo;s future sins but for Israel&rsquo;s coming suffering.</p>",
    "13": "<p>Hazael protests: <strong>meh ʿabdĕkā hakkeleb</strong> — &lsquo;what is your servant, a mere dog?&rsquo; The <em>keleb</em> (dog) self-deprecation formula marks complete lowliness (2 Sam 9:8; 1 Sam 24:14). The rhetorical question <em>kî yaʿăśeh ʿabdĕkā haggedōl hazzeh</em> — &lsquo;that your servant should do this great thing?&rsquo; — uses <em>gāḏôl</em> (great) with bitterness: Hazael protests that the deeds are too great (terrible) for a dog like him to commit. Elisha&rsquo;s answer is blunt: <em>hirʾanî YHWH ʾōtĕkā melek ʿal ʾărām</em>, &lsquo;YHWH has shown me that you will be king over Aram.&rsquo;</p>",
    "14": "<p>Hazael returns to Ben-hadad: <strong>wayyāšob ʾel-ʾăḏōnāyw</strong> — &lsquo;he returned to his master.&rsquo; The king asks, <em>mah ʾāmar lĕkā ʾĕlîšāʿ</em> — &lsquo;What did Elisha say to you?&rsquo; Hazael answers partially: <em>ḥāyōh tiḥyeh</em>, &lsquo;you will certainly recover.&rsquo; He reports only the first half of Elisha&rsquo;s oracle and omits the second (<em>môt yāmût</em>, he will certainly die). The selective report is not marked as a lie by the narrator; the reader alone knows what was left unsaid.</p>",
    "15": "<p><strong>wayyiqqa miqqreh hammāḥărāt</strong> — &lsquo;the next day he took a thick cloth (<em>makbēr</em>) and soaked it in water and spread it over the king&rsquo;s face, and he died.&rsquo; The word <em>makbēr</em> is found only here; likely a thick woven cloth used as a damp smothering agent — not a pillow but a wet cloth blocking respiration. The verb <em>wayyamot</em> (he died) is unadorned: no judgment, no comment, just the bare fact. Hazael&rsquo;s ascension is narrated in the same verse: <em>wayyimlok ḥăzāʾēl taḥtāyw</em>, &lsquo;and Hazael became king in his place.&rsquo;</p>",
    "16": "<p>The narrative shifts to Judah: <strong>ûbišnat ḥāmēš lĕyôrām ben-ʾaḥʾāḇ melek yiśrāʾēl</strong> — &lsquo;in the fifth year of Joram son of Ahab king of Israel.&rsquo; The synchronistic dating formula (aligning Judahite with Israelite regnal years) is the Kings historian&rsquo;s standard method of organizing the divided monarchy&rsquo;s parallel timeline. <em>Malak yĕhôrām ben-yĕhôšāpāṭ melek yĕhûḏāh</em> — Jehoram of Judah begins his reign.</p>",
    "17": "<p><strong>ben-šĕlōšîm ûšĕtayim šānāh hāyāh bĕmalĕkô</strong> — &lsquo;he was thirty-two years old when he became king.&rsquo; The regnal formula follows the standard pattern: age at accession, years of reign, maternal lineage, theological assessment. Jehoram reigned eight years (<em>šmōneh šānîm mālaḵ bîrûšālaim</em>).</p>",
    "18": "<p>The theological assessment: <strong>wayyēlek bĕderek malkê yiśrāʾēl kaʾăšer ʿāśû bêt ʾaḥʾāḇ</strong> — &lsquo;he walked in the way of the kings of Israel, as the house of Ahab had done.&rsquo; The decisive phrase: <em>kî bat-ʾaḥʾāḇ hāyĕtāh lô lĕʾiššāh</em>, &lsquo;for the daughter of Ahab was his wife.&rsquo; The Ahab connection through marriage explains the theological contamination. <em>Hālak bĕderek</em> (walked in the way of) is the Kings historian&rsquo;s standard negative formula, the inverse of &lsquo;walking in the way of David.&rsquo;</p>",
    "19": "<p>The key theological crux: <strong>wĕlōʾ-ʾābāh YHWH lĕhašḥît ʾet-yĕhûḏāh lĕmaʿan dāwîḏ ʿabdô</strong> — &lsquo;Yet YHWH was not willing to destroy Judah, for the sake of his servant David.&rsquo; The phrase <em>lōʾ-ʾābāh</em> (not willing, refused to consent) is the strongest possible expression of YHWH&rsquo;s restraint. The ground: <em>lĕmaʿan dāwîḏ ʿabdô</em>, &lsquo;for the sake of his servant David&rsquo; — the Davidic covenant (2 Sam 7:12-16) functions as a limit on divine judgment. The specific promise is quoted: <em>kĕʾăšer ʾāmar lô lātēt lô nîr lĕbānāyw kol-hayyāmîm</em>, &lsquo;as he had promised to give a lamp to him and to his sons for all time.&rsquo; The <em>nîr</em> (lamp) is a metaphor for the continuing royal line (1 Kgs 11:36; 15:4).</p>",
    "20": "<p><strong>bāyāmîm hāhēm pāšaʿ ʾĕḏôm mittaḥat yad-yĕhûḏāh</strong> — &lsquo;In his days Edom revolted from under Judah&rsquo;s rule.&rsquo; The verb <em>pāšaʿ</em> (revolt, rebel, transgress) is used both for political revolt and for covenant transgression. The Edomite revolt fulfills the oracle of Gen 27:40 (Esau will break free from Jacob&rsquo;s yoke). Edom&rsquo;s independence is framed as covenant history catching up with itself: the yoke of Jacob/Israel was never permanent.</p>",
    "21": "<p><strong>wayyaʿăḇōr yôrām ṣāʿîrāh</strong> — &lsquo;Joram marched to Zair.&rsquo; He &lsquo;rose up by night and struck the Edomites who surrounded him&rsquo; — <em>wayyāqom lāylāh wayyak ʾet-ʾĕḏôm hasson&rsquo;ēb ʾēlāyw</em>. But the continuation is ambiguous: <em>wayyānos hāʿām lĕʾohŏlāyw</em>, &lsquo;the people fled to their tents.&rsquo; It is unclear whether &lsquo;the people&rsquo; refers to Joram&rsquo;s Israelite troops fleeing (military failure) or the Edomites. The ambiguity may be intentional — a botched campaign that neither defeated Edom nor was itself defeated.</p>",
    "22": "<p><strong>wayyipšaʿ ʾĕḏôm mittaḥat yad-yĕhûḏāh ʿaḏ hayyôm hazzeh</strong> — &lsquo;so Edom has been in revolt against Judah to this day.&rsquo; The phrase <em>ʿaḏ hayyôm hazzeh</em> (to this day) is the Kings narrator&rsquo;s way of marking a state that persists until the time of writing. Libnah (<em>liḇnāh gam-hîʾ pāšĕʿāh</em>) also revolted &lsquo;at the same time&rsquo; (<em>bāʿēt hahîʾ</em>). Two simultaneous revolts under a weak king mark the beginning of Judah&rsquo;s political contraction.</p>",
    "23": "<p>The regnal closing formula: <strong>wĕyeter diḇrê yôrām wĕkol-ʾăšer ʿāśāh hălem-hēm kĕtûḇîm ʿal-sēper diḇrê hayyāmîm lĕmalkê yĕhûḏāh</strong> — &lsquo;the rest of the acts of Joram and everything he did, are they not written in the Book of the Annals of the Kings of Judah?&rsquo; This formula, repeated for almost every king, presupposes the reader&rsquo;s access to other records — the Kings narrative is selective, not comprehensive. The historian has chosen which details serve the theological argument about covenant fidelity and its consequences.</p>",
    "24": "<p><strong>wayyiškaḇ yôrām ʿim-ʾăḇōtāyw</strong> — &lsquo;Joram rested with his ancestors.&rsquo; The standard death formula <em>šākab ʿim ʾăḇōtāyw</em> (lay down/slept with his fathers) is used across the Davidic line. The variation <em>wayyiqqāḇēr ʾittām bĕʿîr dāwîḏ</em> — &lsquo;buried with them in the city of David&rsquo; — indicates continuation of the royal burial tradition, despite Joram&rsquo;s apostasy.</p>",
    "25": "<p><strong>bišnat šĕtêm ʿeśrēh šānāh lĕyôrām ben-ʾaḥʾāḇ melek yiśrāʾēl</strong> — the synchronistic formula anchors Ahaziah of Judah&rsquo;s accession to year 12 of Israel&rsquo;s Joram. The two northern and southern reigns are tracked in tandem throughout Kings — the historian&rsquo;s method of maintaining chronological coherence across the divided monarchy.</p>",
    "26": "<p>Ahaziah&rsquo;s regnal formula: <strong>ben-ʿeśrîm ûšĕtayim šānāh</strong> — twenty-two years old. Reigned one year (<em>šānāh ʾaḥat mālaḵ bîrûšālaim</em>). His mother: <em>ʿătalyāhû bat-ʿomrî melek yiśrāʾēl</em>, &lsquo;Athaliah the daughter of Omri king of Israel.&rsquo; The Omride connection through the maternal line (even more proximate than through his father&rsquo;s marriage to an Ahab daughter) marks Ahaziah as doubly contaminated by the house of Ahab.</p>",
    "27": "<p><strong>wayyēlek bĕderek bêt ʾaḥʾāḇ</strong> — &lsquo;he walked in the way of the house of Ahab.&rsquo; The phrase is used four times across Jehoram and Ahaziah (vv18, 27): the Ahab contamination of the Davidic line is the historian&rsquo;s central concern in this section. The theological verdict: <em>wayyaʿaś hārāʿ bĕʿênê YHWH kaʾăšer bêt ʾaḥʾāḇ</em> — &lsquo;he did evil in the sight of YHWH as the house of Ahab had done.&rsquo;</p>",
    "28": "<p>Political narrative: Ahaziah went with Joram son of Ahab to fight against Hazael king of Syria at Ramoth-gilead. The verb <strong>wayyēlek... lammilḥāmāh</strong> — &lsquo;went to war.&rsquo; The mention of Hazael confirms the fulfillment of Elisha&rsquo;s oracle (vv13-15): Hazael is now king of Aram and attacking Israel. The narrative loop closes: Elisha prophesied Hazael&rsquo;s kingship and atrocities; Hazael is now executing them.</p>",
    "29": "<p>Joram is wounded: <strong>wayyāšob yôrām hammelek lĕhitrappēʾ bĕyizrĕʿēl</strong> — &lsquo;King Joram returned to Jezreel to recover from the wounds.&rsquo; The verb <em>rāpāʾ</em> (heal, be healed) — Joram retreats to Jezreel, the Omride winter capital and the site of Naboth&rsquo;s vineyard. The chapter ends with Ahaziah going to Jezreel to visit (<em>lirʾôt</em>, &lsquo;to see&rsquo;) the wounded Joram — a visit that will lead to his own death in the Jehu narrative (ch 9). The narrative tension is established without resolution.</p>"
  }
}

def main():
    existing = load_comm('mkt-original', '2kings')
    merge_comm(existing, KINGS2)
    save_comm('mkt-original', '2kings', existing)
    count = sum(len(v) for v in KINGS2.values())
    print(f'2kings mkt-original ch 6-8: wrote {count} verses')

if __name__ == '__main__':
    main()
